function computeFootprint(triangles: Triangle[]): RoofGeometry['buildingFootprint'] {
  if (triangles.length === 0) {
    return { center: [0, 0, 0], size: [0, 0, 0] };
  }
  let minX = Infinity;
  let minY = Infinity;
  let minZ = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;
  let maxZ = -Infinity;
  for (const t of triangles) {
    const [x, y, z] = t.centroid;
    if (x < minX) minX = x;
    if (x > maxX) maxX = x;
    if (y < minY) minY = y;
    if (y > maxY) maxY = y;
    if (z < minZ) minZ = z;
    if (z > maxZ) maxZ = z;
  }
  return {
    center: [(minX + maxX) / 2, (minY + maxY) / 2, (minZ + maxZ) / 2],
    size: [maxX - minX, maxY - minY, maxZ - minZ],
  };
}

async function analyzeHouse(houseId: string): Promise<RoofGeometry> {
  const photogrammetry = path.join(BAKED_DIR, `${houseId}-photogrammetry.glb`);
  const fallback = path.join(FALLBACK_DIR, `${houseId}.glb`);

  let glbPath = photogrammetry;
  try {
    await fs.access(photogrammetry);
  } catch {
    console.warn(`[${houseId}] photogrammetry missing → falling back to ${fallback}`);
    glbPath = fallback;
  }

  const triangles = await loadTriangles(glbPath);
  console.log(`[${houseId}] loaded ${triangles.length} triangles from ${path.basename(glbPath)}`);

  const roofTris = triangles.filter((t) => t.normal[1] > ROOF_NORMAL_Y_MIN);
  console.log(`[${houseId}] ${roofTris.length} candidate roof triangles after normal filter`);

  const clusters = await clusterRoofFaces(roofTris);
  const sortedClusters = clusters
    .map((c) => c)
    .filter((c) => c.length >= DBSCAN_MIN_POINTS)
    .sort((a, b) => b.length - a.length)
    .slice(0, 6);

  const faces: RoofFace[] = sortedClusters.map((cluster, idx) => {
    const tris = cluster.map((i) => roofTris[i]);
    const normal = meanNormal(tris);
    const azimuth = azimuthFromNormal(normal);
    const tilt = tiltFromNormal(normal);
    const area = tris.reduce((sum, t) => sum + t.area, 0);
    const allPoints = tris.flatMap((t) => t.vertices);
    const vertices = convexHullXZ(allPoints);
    return {
      id: idx,
      normal,
      area: Math.round(area * 10) / 10,
      azimuth: Math.round(azimuth),
      tilt: Math.round(tilt),
      vertices,
      yieldKwhPerSqm: computeYield(azimuth, tilt),
    };
  });

  // Naive obstruction detection: tiny clusters of mostly-vertical normals
  // sitting above the roof plane. Plan-B: skip — the renderer can place
  // chimneys procedurally.
  const obstructions: Obstruction[] = [];

  const buildingFootprint = computeFootprint(triangles);

  const modulePositions = faces.flatMap((face) => placePanelsOnFace(face, obstructions));

  return {
    houseId: houseId as RoofGeometry['houseId'],
    faces,
    obstructions,
    modulePositions,
    buildingFootprint,
  };
}

