  triangles = triangles.filter((t) => Math.hypot(t.centroid[0], t.centroid[2]) < HOUSE_HORIZONTAL_RADIUS_M);
  console.log(`[${houseId}] kept ${triangles.length}/${before} triangles within ${HOUSE_HORIZONTAL_RADIUS_M} m of the address`);
}

