// Per-house surface threshold: small Doppelhaus halves can yield ~10 m²
// total roof area, so each pitch may be 4-6 m². Use a permissive threshold
// that still filters noise (a single noisy triangle has area ~0.05 m²).
const MIN_FACE_AREA_SQM = 1.5;
const significantClusters = clusters.filter((cluster) => {
  const totalArea = cluster.reduce((s, idx) => s + roofTris[idx].area, 0);
  return totalArea > MIN_FACE_AREA_SQM && cluster.length >= DBSCAN_MIN_POINTS;
});
// Diagnostic: print all cluster sizes so we can tell whether a 0-face result
// is "no roof at all" vs. "many tiny clusters that all fell under threshold".
if (sortedClustersIsEmptyHint(significantClusters, clusters, roofTris)) {
  const top = clusters
    .map((c) => ({ count: c.length, area: c.reduce((s, idx) => s + roofTris[idx].area, 0) }))
    .filter((c) => c.count >= DBSCAN_MIN_POINTS)
    .sort((a, b) => b.area - a.area)
    .slice(0, 6);
  if (top.length) {
    console.log(`  diag clusters (count, area):`, top.map((t) => `${t.count}×${t.area.toFixed(1)}m²`).join(', '));
  }
}

