1	// Fetch Google 3D Tiles for the demo addresses — OWNED by Dev D
2	// Run: pnpm bake:fetch
3	//
4	// Goal: download the photogrammetric mesh around each demo address and save
5	// it as a local GLB. The raw mesh is used OFFLINE only for roof analysis;
6	// it is NEVER rendered in the user-facing demo.
7	//
8	// Strategy:
9	// 1. TilesRenderer + GoogleCloudAuthPlugin pointed at a virtual camera over (lat, lng).
10	// 2. Pump tiles.update() in a loop until queues are empty (downloading + parsing).
11	// 3. Walk tiles.group, collect all THREE.Mesh, crop to a ~80×80 m bbox around the
12	//    target ECEF position, merge into a single Group.
13	// 4. Export with GLTFExporter (binary GLB) and write to public/baked/{house}-photogrammetry.glb.
14	//
15	// IMPORTANT: 3d-tiles-renderer is browser-first. We bridge to Node by polyfilling
16	// the bare minimum DOM (fetch, ImageBitmap-via-sharp). If that proves too painful
17	// in the 2h hard timebox → Plan B: serve a small Vite page that downloads the GLB
18	// in the browser and `URL.createObjectURL` → manual save.
19	
20	import { promises as fs } from 'node:fs';
21	import path from 'node:path';
22	
23	// Minimal browser-globals polyfill — 3d-tiles-renderer + GLTFExporter assume DOM.
24	// Must run BEFORE three / 3d-tiles-renderer imports resolve.
25	const g = globalThis as unknown as Record<string, unknown>;
26	
27	// Patch URL.createObjectURL FIRST — GLTFLoader captures it on the global URL
28	// at module load time, so it must exist before three's GLTFLoader is imported.
29	const URLCtor = g.URL as unknown as { createObjectURL?: (b: unknown) => string; revokeObjectURL?: (u: string) => void };
30	if (URLCtor && !URLCtor.createObjectURL) {
31	  URLCtor.createObjectURL = () => 'data:application/octet-stream;base64,';
32	  URLCtor.revokeObjectURL = () => undefined;
33	}
34	
35	// `window` / `self` must alias globalThis so things like `self.URL.createObjectURL`,
36	// `self.fetch`, etc. resolve to the Node globals rather than empty stubs.
37	if (!g.location) g.location = { href: 'https://localhost/', origin: 'https://localhost' };
38	if (!g.window) g.window = globalThis;
39	if (!g.self) g.self = globalThis;
40	if (!g.document) {
41	  g.document = {
42	    createElementNS: () => ({ style: {} }),
43	    createElement: () => ({ style: {} }),
44	  };
45	}
46	// 3d-tiles-renderer's Scheduler uses rAF for off-main-thread work pacing.
47	// In Node, fall back to setImmediate (ticks asap, no 16ms gating).
48	if (!g.requestAnimationFrame) {
49	  g.requestAnimationFrame = (cb: (t: number) => void) => setImmediate(() => cb(performance.now())) as unknown as number;
50	  g.cancelAnimationFrame = (id: number) => clearImmediate(id as unknown as NodeJS.Immediate);
51	}
52	// GLTFExporter uses FileReader to convert images to data URIs. Stub it —
53	// our exported GLB only carries geometry, no embedded images.
54	if (!g.FileReader) {
55	  class FileReaderStub {
56	    result: string | null = null;
57	    onload: (() => void) | null = null;
58	    onerror: (() => void) | null = null;
59	    readAsDataURL() { this.result = 'data:application/octet-stream;base64,'; this.onload?.(); }
60	    readAsArrayBuffer() { this.result = ''; this.onload?.(); }
61	  }
62	  g.FileReader = FileReaderStub;
63	}
64	// Image loading: GLTFLoader uses ImageLoader → new Image(). Skip texture loads
65	// entirely by returning a stub object that immediately fires onload.
66	if (!g.Image) {
67	  class ImageStub {
68	    src = '';
69	    onload: (() => void) | null = null;
70	    onerror: (() => void) | null = null;
71	    width = 1;
72	    height = 1;
73	    addEventListener(ev: string, cb: () => void) { if (ev === 'load') setImmediate(cb); }
74	    removeEventListener() {}
75	  }
76	  g.Image = ImageStub;
77	}
78	// createImageBitmap: same idea — return a tiny stub.
79	if (!g.createImageBitmap) {
80	  g.createImageBitmap = async () => ({ width: 1, height: 1, close: () => undefined });
81	}
82	// ImageBitmap class is referenced by 3d-tiles-renderer when disposing tiles
83	// (instanceof checks). A dummy class is enough to satisfy the check.
84	if (!g.ImageBitmap) {
85	  class ImageBitmapStub { close() {} }
86	  g.ImageBitmap = ImageBitmapStub;
87	}
