79	function buildTrianglesFromArrays(positions: ArrayLike<number>, indices: ArrayLike<number>): Triangle[] {
80	  const triangles: Triangle[] = [];
81	  const triCount = indices.length / 3;
82	  for (let t = 0; t < triCount; t++) {
83	    const i0 = indices[t * 3];
84	    const i1 = indices[t * 3 + 1];
85	    const i2 = indices[t * 3 + 2];
86	
87	    const v0: [number, number, number] = [positions[i0 * 3], positions[i0 * 3 + 1], positions[i0 * 3 + 2]];
88	    const v1: [number, number, number] = [positions[i1 * 3], positions[i1 * 3 + 1], positions[i1 * 3 + 2]];
89	    const v2: [number, number, number] = [positions[i2 * 3], positions[i2 * 3 + 1], positions[i2 * 3 + 2]];
90	
91	    const ax = v1[0] - v0[0];
92	    const ay = v1[1] - v0[1];
93	    const az = v1[2] - v0[2];
94	    const bx = v2[0] - v0[0];
95	    const by = v2[1] - v0[1];
96	    const bz = v2[2] - v0[2];
97	
98	    const cx = ay * bz - az * by;
99	    const cy = az * bx - ax * bz;
100	    const cz = ax * by - ay * bx;
101	    const len = Math.hypot(cx, cy, cz);
102	    if (len < 1e-8) continue;
103	
104	    const area = len * 0.5;
105	    const normal: [number, number, number] = [cx / len, cy / len, cz / len];
106	    const centroid: [number, number, number] = [
107	      (v0[0] + v1[0] + v2[0]) / 3,
108	      (v0[1] + v1[1] + v2[1]) / 3,
109	      (v0[2] + v1[2] + v2[2]) / 3,
110	    ];
111	    triangles.push({ centroid, normal, area, vertices: [v0, v1, v2] });
112	  }
113	  return triangles;
114	}
