118	  const data = JSON.parse(raw) as { positions: number[]; indices: number[]; lat?: number; lng?: number };
119	  const triangles = buildTrianglesFromArrays(data.positions, data.indices);
120	  const origin = typeof data.lat === 'number' && typeof data.lng === 'number' ? { lat: data.lat, lng: data.lng } : null;
121	  return { triangles, origin };
